return [{
  json: {
    body: {
      dealId: 'deal-001',
      source: 'n8n-manual-demo',
      trigger: 'manual_demo_run',
      proof_need: 'Find public-sector proof for Camden Integrated Care Board before the board prep call.',
      events: [
        {
          event_id: `n8n_manual_${Date.now()}`,
          type: 'manual.demo',
          id: {
            workspace_id: 'wrk_demo',
            object_id: 'obj_deals',
            record_id: 'deal-001'
          }
        }
      ]
    },
    headers: {}
  }
}];

const body = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const headers = $json.headers && typeof $json.headers === 'object' ? $json.headers : {};
const firstEvent = Array.isArray(body.events) ? body.events[0] : undefined;
const eventRecordId = firstEvent?.id?.record_id || firstEvent?.data?.record_id;
const dealId = body.dealId || body.deal_id || body.recordId || body.record_id || eventRecordId || body.deal?.id;

if (!dealId && !body.deal) {
  throw new Error('ProofOps needs either dealId or an inline deal payload.');
}

const headerIdempotency = headers['idempotency-key'] || headers['Idempotency-Key'];
const eventId = firstEvent?.event_id || firstEvent?.id;
const idempotencyKey = body.idempotencyKey || body.idempotency_key || headerIdempotency || eventId || `n8n-proofops-${dealId || Date.now()}`;
const proofopsUrl = body.proofopsUrl || 'https://proofops.vercel.app/api/attio/workflow';

return [{
  json: {
    proofopsUrl,
    proofopsSecret: body.proofopsSecret || '',
    idempotencyKey: String(idempotencyKey),
    payload: {
      ...body,
      dealId,
      source: body.source || 'n8n-attio-workflow',
      trigger: body.trigger || body.event_type || firstEvent?.type || 'n8n_webhook',
      events: Array.isArray(body.events) ? body.events : [
        {
          event_id: String(idempotencyKey),
          type: body.event_type || 'n8n.webhook',
          id: {
            record_id: dealId
          }
        }
      ]
    }
  }
}];

const statusCode = Number($json.statusCode || 200);
let proofRun = $json.body || $json;

if (typeof proofRun === 'string') {
  try {
    proofRun = JSON.parse(proofRun);
  } catch {
    proofRun = { raw: proofRun };
  }
}

const bestMatch = Array.isArray(proofRun.matches) ? proofRun.matches[0] : undefined;
const ok = statusCode >= 200 && statusCode < 300 && !proofRun.error;

return [{
  json: {
    ok,
    statusCode,
    response: {
      ok,
      statusCode,
      deal: proofRun.deal?.company || proofRun.deal?.id || null,
      bestMatch: bestMatch?.company || null,
      consent: bestMatch?.consent || null,
      retrievalProvider: proofRun.retrievalProvider || null,
      evidenceProvider: proofRun.evidenceProvider || null,
      reasoningProvider: proofRun.reasoningProvider || null,
      attioWriteStatus: proofRun.attioWrite?.status || null,
      duplicateSuppressed: Boolean(proofRun.security?.duplicateSuppressed),
      idempotencyKey: proofRun.idempotencyKey || null,
      trace: Array.isArray(proofRun.trace) ? proofRun.trace.map((step) => ({ label: step.label, status: step.status })) : [],
      error: proofRun.error || null
    },
    proofRun
  }
}];
